import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/SupabaseContext';
import { useBrand } from '../context/BrandContext';
import { useGeminiGeneration } from '../hooks/useGeminiGeneration';
import { useToast } from '../components/ui/Toast';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface HeatmapEntry {
  skill: string;
  region: string;
  demandScore: number;
  jobCount: number;
  avgSalary: number;
}

interface TrendingSkill {
  skill: string;
  trend: 'rising' | 'stable' | 'declining';
  score: number;
}

interface HeatmapData {
  skills: string[];
  regions: string[];
  heatmap: HeatmapEntry[];
  trending: TrendingSkill[];
  insights: string[];
}

function getDemandColor(score: number): string {
  if (score >= 81) return '#ef4444';
  if (score >= 61) return '#f59e0b';
  if (score >= 31) return '#4a9079';
  return '#1e3a5f';
}

function getDemandLabel(score: number): string {
  if (score >= 81) return 'Very High';
  if (score >= 61) return 'High';
  if (score >= 31) return 'Moderate';
  return 'Low';
}

function getTrendIcon(trend: string): string {
  if (trend === 'rising') return 'fa-arrow-trend-up';
  if (trend === 'declining') return 'fa-arrow-trend-down';
  return 'fa-minus';
}

function getTrendColor(trend: string): string {
  if (trend === 'rising') return '#10b981';
  if (trend === 'declining') return '#ef4444';
  return '#f59e0b';
}

export default function JobMarketHeatmapPage() {
  const { user, isPremium, isLoading: authLoading } = useAuth();
  const brand = useBrand();
  const navigate = useNavigate();
  const { generate, isGenerating } = useGeminiGeneration();
  const { showToast } = useToast();

  const [skills, setSkills] = useState('');
  const [country, setCountry] = useState('US');
  const [data, setData] = useState<HeatmapData | null>(null);

  useEffect(() => {
    if (!authLoading && !user) navigate('/login');
    if (!authLoading && user && !isPremium) navigate('/pricing');
  }, [authLoading, user, isPremium, navigate]);

  async function handleGenerate() {
    if (!skills.trim()) { showToast('Please enter at least one skill.', true); return; }

    const systemPrompt = `You are a job market analyst with real-time knowledge of tech hiring trends.

Given a list of skills and a country, analyze job market demand across major metropolitan areas.

CRITICAL: Respond with ONLY a single \`\`\`json code block containing a JSON object with this exact structure:
{
  "skills": ["React", "Python", "AWS"],
  "regions": ["San Francisco", "New York", "Austin", "Seattle", "Chicago", "Boston", "Denver", "Los Angeles", "Miami", "Remote"],
  "heatmap": [
    { "skill": "React", "region": "San Francisco", "demandScore": 95, "jobCount": 2340, "avgSalary": 185000 }
  ],
  "trending": [
    { "skill": "Rust", "trend": "rising", "score": 72 }
  ],
  "insights": ["insight 1", "insight 2", "insight 3"]
}

Include ALL combinations of skills x regions in the heatmap array.
demandScore is 0-100. jobCount is estimated open positions. avgSalary is annual USD.
Include 5-8 trending related skills. Make data realistic for 2025-2026.`;

    const userPrompt = `Skills: ${skills}\nCountry: ${country}`;

    const result = await generate({ systemPrompt, userPrompt, timeout: 60000 });
    if (!result?.rawText) return;

    try {
      const jsonMatch = result.rawText.match(/```json\s*([\s\S]*?)```/) || result.rawText.match(/```\s*([\s\S]*?)```/);
      if (jsonMatch) {
        setData(JSON.parse(jsonMatch[1]) as HeatmapData);
      } else {
        setData(JSON.parse(result.rawText) as HeatmapData);
      }
    } catch {
      showToast('Failed to parse market data. Please try again.', true);
    }
  }

  if (authLoading) return null;

  // Build grid data for the first skill (for top regions chart)
  const primarySkill = data?.skills?.[0];
  const topRegionsData = data?.heatmap
    ?.filter(h => h.skill === primarySkill)
    ?.sort((a, b) => b.demandScore - a.demandScore)
    ?.slice(0, 10) || [];

  return (
    <div style={{ maxWidth: '1000px', margin: '0 auto', padding: '2rem 1.5rem' }}>
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '1.5rem' }}>
        <div style={{ width: '48px', height: '48px', borderRadius: '2px', background: brand.primaryColor, display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff', fontSize: '1.2rem' }}>
          <i className="fa-solid fa-map-location-dot" />
        </div>
        <div>
          <h1 style={{ fontSize: '1.5rem', margin: 0, color: 'var(--text-primary)' }}>Job Market Heatmap</h1>
          <p style={{ margin: 0, fontSize: '0.82rem', color: 'var(--text-secondary)' }}>Visual demand analysis by skill and region</p>
        </div>
      </div>

      {/* Input Form */}
      <div className="glass-panel" style={{ padding: '1.5rem', marginBottom: '1.5rem' }}>
        <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '1rem' }}>
          <div>
            <label style={{ display: 'block', fontSize: '0.78rem', fontWeight: 600, color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>Skills (comma-separated) *</label>
            <input value={skills} onChange={e => setSkills(e.target.value)} placeholder="e.g., React, Python, AWS, TypeScript" style={{ width: '100%' }} />
          </div>
          <div>
            <label style={{ display: 'block', fontSize: '0.78rem', fontWeight: 600, color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>Country</label>
            <select value={country} onChange={e => setCountry(e.target.value)} style={{ width: '100%' }}>
              <option value="US">United States</option>
              <option value="UK">United Kingdom</option>
              <option value="CA">Canada</option>
              <option value="Remote">Remote / Global</option>
            </select>
          </div>
        </div>

        <button
          onClick={handleGenerate}
          disabled={isGenerating}
          className="btn secondary-btn"
          style={{ marginTop: '1.25rem', width: '100%', padding: '0.75rem', fontSize: '0.95rem', cursor: isGenerating ? 'not-allowed' : 'pointer' }}
        >
          {isGenerating ? <><i className="fa-solid fa-spinner fa-spin" /> Analyzing market demand...</> : <><i className="fa-solid fa-fire" /> Generate Heatmap</>}
        </button>
      </div>

      {/* Results */}
      {data && (
        <>
          {/* Heatmap Grid */}
          <div className="glass-panel" style={{ padding: '1.25rem', marginBottom: '1.5rem', overflowX: 'auto' }}>
            <h3 style={{ fontSize: '0.9rem', margin: '0 0 1rem', color: 'var(--text-primary)' }}>Demand Heatmap</h3>

            {/* Legend */}
            <div style={{ display: 'flex', gap: '1rem', marginBottom: '0.75rem', fontSize: '0.7rem', color: 'var(--text-secondary)' }}>
              {[{ label: 'Low (0-30)', color: '#1e3a5f' }, { label: 'Moderate (31-60)', color: '#4a9079' }, { label: 'High (61-80)', color: '#f59e0b' }, { label: 'Very High (81-100)', color: '#ef4444' }].map(l => (
                <span key={l.label} style={{ display: 'flex', alignItems: 'center', gap: '0.3rem' }}>
                  <span style={{ width: '12px', height: '12px', borderRadius: '2px', background: l.color, display: 'inline-block' }} />
                  {l.label}
                </span>
              ))}
            </div>

            {/* Grid */}
            <div style={{ display: 'grid', gridTemplateColumns: `120px repeat(${data.regions.length}, 1fr)`, gap: '2px', minWidth: `${120 + data.regions.length * 80}px` }}>
              {/* Header row */}
              <div />
              {data.regions.map(r => (
                <div key={r} style={{ fontSize: '0.65rem', fontWeight: 600, color: 'var(--text-secondary)', textAlign: 'center', padding: '0.3rem', writingMode: 'vertical-rl', transform: 'rotate(180deg)', height: '80px' }}>
                  {r}
                </div>
              ))}

              {/* Data rows */}
              {data.skills.map(skill => (
                <React.Fragment key={skill}>
                  <div style={{ fontSize: '0.78rem', fontWeight: 600, color: 'var(--text-primary)', display: 'flex', alignItems: 'center', padding: '0 0.25rem' }}>
                    {skill}
                  </div>
                  {data.regions.map(region => {
                    const entry = data.heatmap.find(h => h.skill === skill && h.region === region);
                    const score = entry?.demandScore || 0;
                    return (
                      <div
                        key={`${skill}-${region}`}
                        title={`${skill} in ${region}: ${score}/100 demand, ~${entry?.jobCount || 0} jobs, ~$${((entry?.avgSalary || 0) / 1000).toFixed(0)}k avg`}
                        style={{
                          background: getDemandColor(score),
                          borderRadius: '4px',
                          padding: '0.4rem',
                          textAlign: 'center',
                          cursor: 'default',
                          minHeight: '44px',
                          display: 'flex',
                          flexDirection: 'column',
                          alignItems: 'center',
                          justifyContent: 'center',
                        }}
                      >
                        <div style={{ fontSize: '0.85rem', fontWeight: 700, color: '#fff' }}>{score}</div>
                        <div style={{ fontSize: '0.55rem', color: 'rgba(255,255,255,0.7)' }}>{entry?.jobCount ? `${(entry.jobCount / 1000).toFixed(1)}k` : ''}</div>
                      </div>
                    );
                  })}
                </React.Fragment>
              ))}
            </div>
          </div>

          {/* Top Regions Bar Chart */}
          {topRegionsData.length > 0 && (
            <div className="glass-panel" style={{ padding: '1.25rem', marginBottom: '1.5rem' }}>
              <h3 style={{ fontSize: '0.9rem', margin: '0 0 1rem', color: 'var(--text-primary)' }}>Top Regions for {primarySkill}</h3>
              <ResponsiveContainer width="100%" height={250}>
                <BarChart data={topRegionsData}>
                  <XAxis dataKey="region" tick={{ fill: 'var(--text-secondary)', fontSize: 10 }} angle={-30} textAnchor="end" height={60} />
                  <YAxis tick={{ fill: 'var(--text-secondary)', fontSize: 11 }} domain={[0, 100]} />
                  <Tooltip contentStyle={{ background: 'var(--panel-bg)', border: '1px solid var(--panel-border)', borderRadius: '8px', fontSize: '0.82rem' }} formatter={(v: number | undefined, name?: string) => [v ?? 0, name === 'demandScore' ? 'Demand Score' : (name ?? '')]} />
                  <Bar dataKey="demandScore" radius={[4, 4, 0, 0]}>
                    {topRegionsData.map((entry, i) => (
                      <Cell key={i} fill={getDemandColor(entry.demandScore)} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
          )}

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem' }}>
            {/* Trending Skills */}
            <div className="glass-panel" style={{ padding: '1.25rem' }}>
              <h3 style={{ fontSize: '0.9rem', margin: '0 0 0.75rem', color: 'var(--text-primary)' }}>Trending Related Skills</h3>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                {data.trending.map(t => (
                  <div key={t.skill} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0.4rem 0', borderBottom: '1px solid var(--panel-border)' }}>
                    <span style={{ fontSize: '0.85rem', color: 'var(--text-primary)' }}>{t.skill}</span>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                      <span style={{ fontSize: '0.78rem', fontWeight: 600, color: 'var(--text-secondary)' }}>{t.score}</span>
                      <i className={`fa-solid ${getTrendIcon(t.trend)}`} style={{ color: getTrendColor(t.trend), fontSize: '0.75rem' }} />
                      <span style={{ fontSize: '0.7rem', color: getTrendColor(t.trend), textTransform: 'capitalize' }}>{t.trend}</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Insights */}
            <div className="glass-panel" style={{ padding: '1.25rem' }}>
              <h3 style={{ fontSize: '0.9rem', margin: '0 0 0.75rem', color: 'var(--text-primary)' }}>Market Insights</h3>
              <ul style={{ listStyle: 'none', padding: 0, margin: 0, display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                {data.insights.map((insight, i) => (
                  <li key={i} style={{ fontSize: '0.82rem', color: 'var(--text-secondary)', display: 'flex', gap: '0.5rem', lineHeight: 1.5 }}>
                    <i className="fa-solid fa-chart-pie" style={{ color: brand.primaryColor, marginTop: '0.15rem', flexShrink: 0 }} />
                    {insight}
                  </li>
                ))}
              </ul>
            </div>
          </div>
        </>
      )}
    </div>
  );
}
